// SPLLexerInit initializes any static state used to implement SPLLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewSPLLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func SPLLexerInit() {
	staticData := &SPLLexerLexerStaticData
	staticData.once.Do(spllexerLexerInit)
}

// NewSPLLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewSPLLexer(input antlr.CharStream) *SPLLexer {
	SPLLexerInit()
	l := new(SPLLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &SPLLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "SPLLexer.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

